<script lang='ts'>import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import PageHeader from '$lib/components/PageHeader.svelte';import AdminSection from '$lib/components/AdminSection.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminGoLiveChecklist, type GoLiveChecklistResponse} from '$lib/api';import GoLiveChecklist from '$lib/components/GoLiveChecklist.svelte';let d:GoLiveChecklistResponse={items:[]};let error='';const load=async()=>{try{d=await fetchAdminGoLiveChecklist();}catch(e:any){error=e.message||'Erreur';}};onMount(load);$:ok=d.items.filter(i=>i.status==='ok').length;</script>
<AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<PageHeader title="Go-live checklist" subtitle="Préparation VPS"/><button on:click={load}>Refresh checklist</button><p>OK: {ok}/{d.items.length}</p><a href="https://github.com/Alidrix/The_Trend_Scope/blob/main/docs/production.md" target="_blank" rel="noreferrer">docs/production.md</a>{#if error}<p>{error}</p>{/if}<AdminSection title="Checklist"><GoLiveChecklist items={d.items}/></AdminSection>{/if}</AppShell>
